 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  Alert,
 5	  AlertVariant,
 6	  Button,
 7	  EmptyState,
 8	  EmptyStateActions,
 9	  EmptyStateBody,
10	  EmptyStateFooter,
11	  EmptyStateHeader,
12	  EmptyStateVariant,
13	} from '@patternfly/react-core';
14	
15	// Display and empty with a Call to add new source if no sources are defined.
16	export const BootOrderEmptyState: FC<BootOrderEmptyProps> = ({
17	  addItemDisabledMessage,
18	  addItemIsDisabled,
19	  addItemMessage,
20	  message,
21	  onClick,
22	  title,
23	}) => (
24	  <EmptyState variant={EmptyStateVariant.full}>
25	    <EmptyStateHeader headingLevel="h5" titleText={<>{title}</>} />
26	    <EmptyStateBody>{message}</EmptyStateBody>
27	    <EmptyStateFooter>
28	      <EmptyStateActions>
29	        {!addItemIsDisabled ? (
30	          <Button onClick={onClick} variant="secondary">
31	            {addItemMessage}
32	          </Button>
33	        ) : (
34	          <Alert title={addItemDisabledMessage} variant={AlertVariant.info} />
35	        )}
36	      </EmptyStateActions>
37	    </EmptyStateFooter>
38	  </EmptyState>
39	);
40	
41	export type BootOrderEmptyProps = {
42	  addItemDisabledMessage?: string;
43	  addItemIsDisabled: boolean;
44	  addItemMessage: string;
45	  message: string;
46	  onClick: () => void;
47	  title: string;
48	};

